const BASE = 'https://n8n-4d54.onrender.com/api/v1';

const workflows = {"WF-301 SEO Content": "xPhhEHGFbGHjfZN7", "WF-204 Yandex Recrawl": "ayh2yYy0u5p3tWap", "WF-201 GSC+GA4": "1EcezAM2sWYv6WSL", "CEO Brief": "YVH67YNAB44TlTee", "WF-205 SEO Audit": "jzA0CgaqzrXBYUu5"};
const errors = [];
const ok = [];

for (const [name, id] of Object.entries(workflows)) {
  try {
    const resp = await fetch(`${BASE}/executions?workflowId=${id}&limit=1`, {
      headers: { 'X-N8N-API-KEY': N8N_KEY }
    });
    const data = await resp.json();
    const last = (data.data || [])[0];
    if (!last) { errors.push(`⚠️ ${name}: нет запусков`); continue; }
    const age = (Date.now() - new Date(last.stoppedAt).getTime()) / 3600000;
    if (last.status === 'error') {
      errors.push(`❌ ${name}\n   Упал ${Math.round(age)}ч назад`);
    } else if (last.status === 'success') {
      ok.push(`✅ ${name} (${Math.round(age)}ч)`);
    } else {
      errors.push(`⚠️ ${name}: статус ${last.status}`);
    }
  } catch(e) {
    errors.push(`❌ ${name}: ${e.message}`);
  }
}

const msk = new Date(Date.now() + 3*3600000);
const timeStr = msk.toLocaleString('ru-RU', {timeZone:'UTC', hour:'2-digit', minute:'2-digit'});

let msg;
if (errors.length === 0) {
  msg = `✅ Все воркфлоу работают нормально (${timeStr} MSK)\n\n${ok.join('\n')}`;
} else {
  msg = `🚨 АЛЕРТ: ${errors.length} проблем(${timeStr} MSK)\n\n${errors.join('\n\n')}\n\n✅ Работают:\n${ok.join('\n')}`;
}

return [{ json: { text: msg, has_errors: errors.length > 0 } }];
